import React from 'react';
import { motion } from 'framer-motion';
import Logo from './Logo';

const Hero: React.FC = () => {
  return (
    <section id="home" className="relative min-h-screen flex items-center justify-center overflow-hidden bg-gradient-to-br from-white via-[#f5f5f0] to-white">
      {/* Animated background elements */}
      <div className="absolute inset-0">
        {/* Blueprint grid lines */}
        <svg className="absolute inset-0 w-full h-full opacity-5">
          <defs>
            <pattern id="grid" width="40" height="40" patternUnits="userSpaceOnUse">
              <path d="M 40 0 L 0 0 0 40" fill="none" stroke="#5b3e31" strokeWidth="1"/>
            </pattern>
          </defs>
          <rect width="100%" height="100%" fill="url(#grid)" />
        </svg>
        
        {/* Floating design elements */}
        {[...Array(4)].map((_, i) => (
          <motion.div
            key={i}
            className="absolute rounded-full bg-gradient-to-r from-[#5b3e31]/5 to-[#3d3b3a]/5 blur-3xl"
            style={{
              width: Math.random() * 300 + 200,
              height: Math.random() * 300 + 200,
              left: `${Math.random() * 100}%`,
              top: `${Math.random() * 100}%`,
            }}
            animate={{
              x: [0, Math.random() * 100 - 50],
              y: [0, Math.random() * 100 - 50],
              scale: [1, 1.2, 1],
            }}
            transition={{
              duration: 8 + Math.random() * 4,
              repeat: Infinity,
              ease: "easeInOut",
              delay: Math.random() * 2,
            }}
          />
        ))}
        
        {/* Floating design tools */}
        <motion.div
          className="absolute top-20 left-10 text-6xl opacity-10"
          animate={{
            rotate: [0, 360],
            y: [0, -20, 0],
          }}
          transition={{
            duration: 20,
            repeat: Infinity,
            ease: "linear"
          }}
        >
          📐
        </motion.div>
        
        <motion.div
          className="absolute top-40 right-20 text-5xl opacity-10"
          animate={{
            rotate: [0, -360],
            y: [0, 20, 0],
          }}
          transition={{
            duration: 25,
            repeat: Infinity,
            ease: "linear"
          }}
        >
          🏗️
        </motion.div>
        
        <motion.div
          className="absolute bottom-40 left-20 text-5xl opacity-10"
          animate={{
            rotate: [0, 180],
            x: [0, 30, 0],
          }}
          transition={{
            duration: 15,
            repeat: Infinity,
            ease: "easeInOut"
          }}
        >
          🎨
        </motion.div>
        
        {/* Room outline sketch */}
        <motion.svg
          className="absolute bottom-20 right-10 w-64 h-64 opacity-5"
          viewBox="0 0 200 200"
          initial={{ pathLength: 0 }}
          animate={{ pathLength: 1 }}
          transition={{ duration: 3, delay: 2 }}
        >
          <motion.rect
            x="20" y="20" width="160" height="160"
            stroke="#5b3e31"
            strokeWidth="2"
            fill="none"
          />
          <motion.line
            x1="20" y1="100" x2="180" y2="100"
            stroke="#5b3e31"
            strokeWidth="1"
            fill="none"
          />
          <motion.rect
            x="40" y="40" width="60" height="60"
            stroke="#5b3e31"
            strokeWidth="1"
            fill="none"
          />
          <motion.rect
            x="120" y="40" width="40" height="60"
            stroke="#5b3e31"
            strokeWidth="1"
            fill="none"
          />
        </motion.svg>
      </div>

      <div className="relative z-10 container mx-auto px-6 text-center">
        <motion.div
          initial={{ scale: 0 }}
          animate={{ scale: 1 }}
          transition={{ duration: 0.8, ease: "easeOut" }}
          className="mb-8"
        >
          <Logo size="large" />
        </motion.div>

        <motion.h1
          className="text-5xl md:text-7xl font-bold mb-6"
          initial={{ opacity: 0, x: -200, rotateY: 90 }}
          animate={{ opacity: 1, x: 0, rotateY: 0 }}
          transition={{ 
            duration: 1.2, 
            delay: 0.3,
            type: "spring",
            stiffness: 100,
            damping: 20
          }}
        >
          <motion.span 
            className="gradient-text inline-block"
            whileHover={{ 
              scale: 1.05,
              textShadow: "0 0 30px rgba(91, 62, 49, 0.5)"
            }}
            transition={{ duration: 0.3 }}
          >
            {Array.from("MM Spaces").map((letter, index) => (
              <motion.span
                key={index}
                initial={{ opacity: 0, y: 50, rotateZ: Math.random() * 20 - 10 }}
                animate={{ opacity: 1, y: 0, rotateZ: 0 }}
                transition={{
                  duration: 0.8,
                  delay: 0.3 + index * 0.1,
                  type: "spring",
                  stiffness: 200
                }}
                whileHover={{
                  scale: 1.2,
                  color: "#5b3e31"
                }}
              >
                {letter === " " ? "\u00A0" : letter}
              </motion.span>
            ))}
          </motion.span>
        </motion.h1>

        <motion.h2
          className="text-2xl md:text-4xl font-light mb-8 text-[#3d3b3a] elegant-text"
          initial={{ opacity: 0, x: 100, skewX: 20 }}
          animate={{ opacity: 1, x: 0, skewX: 0 }}
          transition={{ 
            duration: 1, 
            delay: 1.2,
            type: "spring",
            stiffness: 80
          }}
        >
          Interior Design
        </motion.h2>

        <motion.p
          className="text-lg md:text-xl text-[#3d3b3a] mb-12 max-w-2xl mx-auto elegant-text"
          initial={{ opacity: 0, scale: 0.5, rotate: 180 }}
          animate={{ opacity: 1, scale: 1, rotate: 0 }}
          transition={{ 
            duration: 1.5, 
            delay: 1.5,
            type: "spring",
            stiffness: 60,
            damping: 15
          }}
        >
          Design that inspire
        </motion.p>

        <motion.div
          className="flex flex-col sm:flex-row gap-4 justify-center items-center"
          initial={{ opacity: 0, y: 50 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ 
            duration: 1, 
            delay: 1.8,
            type: "spring",
            stiffness: 100
          }}
        >
          <motion.a
            href="#services"
            className="px-8 py-4 bg-gradient-to-r from-[#5b3e31] to-[#000000] text-[#ffffff] rounded-full font-semibold hover:shadow-lg hover:shadow-[#5b3e31]/25 transition-all duration-300"
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            Explore Our Work
          </motion.a>
          
          <motion.a
            href="#contact"
            className="px-8 py-4 border border-[#3d3b3a] text-[#3d3b3a] rounded-full font-semibold hover:bg-[#5b3e31] hover:text-[#ffffff] transition-all duration-300"
            whileHover={{ scale: 1.05 }}
            whileTap={{ scale: 0.95 }}
          >
            Get In Touch
          </motion.a>
        </motion.div>

        <motion.div
          className="absolute bottom-8 left-1/2 transform -translate-x-1/2"
          animate={{ y: [0, 10, 0] }}
          transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
        >
          <svg className="w-6 h-6 text-[#3d3b3a]" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 14l-7 7m0 0l-7-7m7 7V3" />
          </svg>
        </motion.div>
      </div>
    </section>
  );
};

export default Hero;
